ads-017.validationNotes:
# Check Spooler on all DCs
Get-ADDomainController -Filter * | ForEach-Object {
  $svc = Get-Service -Name Spooler -ComputerName $_.HostName -ErrorAction SilentlyContinue
  [PSCustomObject]@{
    DC = $_.HostName
    Status = $svc.Status
    StartType = $svc.StartType
  }
} | Format-Table
